
use strand_quant::codebook::{build_codebook_lut_f64, build_quantile_lut_f64};
use strand_quant::trellis::TrellisConfig;

fn fnv1a(quant: &[Vec<i32>], code: &[Vec<i32>]) -> u64 {
    let mut h: u64 = 0xcbf2_9ce4_8422_2325;
    let mut feed = |v: i32| {
        for b in v.to_le_bytes() {
            h ^= b as u64;
            h = h.wrapping_mul(0x0000_0100_0000_01b3);
        }
    };
    for t in quant {
        for &v in t {
            feed(v);
        }
    }
    for t in code {
        for &v in t {
            feed(v);
        }
    }
    h
}

fn main() {
    let lo = TrellisConfig::MIN_L;
    let hi = TrellisConfig::MAX_L;

    let quant: Vec<Vec<i32>> = (lo..=hi).map(build_quantile_lut_f64).collect();
    let code: Vec<Vec<i32>> = (lo..=hi).map(build_codebook_lut_f64).collect();
    let golden = fnv1a(&quant, &code);

    let mut out = String::new();
    out.push_str("//! AUTO-GENERATED by `cargo run -p strand-quant --bin freeze-lut`. DO NOT EDIT.\n");
    out.push_str("//!\n");
    out.push_str("//! Frozen integer quantile/codebook tables for register widths\n");
    out.push_str(&format!("//! `L in [{lo}, {hi}]`, indexed as `LUT[L - MIN_L]`. The deterministic decode\n"));
    out.push_str("//! path reads these as `&'static [i32]` and touches no float code. A golden\n");
    out.push_str("//! FNV-1a hash ([`LUT_GOLDEN_HASH`]) is asserted in tests to catch any drift.\n\n");
    out.push_str(&format!("/// Smallest register width baked into the frozen tables.\npub const FROZEN_MIN_L: u32 = {lo};\n"));
    out.push_str(&format!("/// Largest register width baked into the frozen tables.\npub const FROZEN_MAX_L: u32 = {hi};\n\n"));
    out.push_str("/// Golden FNV-1a hash over all frozen table bytes (drift sentinel).\n");
    out.push_str(&format!("pub const LUT_GOLDEN_HASH: u64 = 0x{golden:016x};\n\n"));

    out.push_str("/// Frozen quantile tables (Q12), one per `L`, indexed `[L - FROZEN_MIN_L]`.\n");
    out.push_str("#[rustfmt::skip]\n");
    out.push_str("pub static QUANTILE_LUTS: &[&[i32]] = &[\n");
    for (k, t) in quant.iter().enumerate() {
        out.push_str(&format!("    // L = {}\n    &[", lo as usize + k));
        for (i, v) in t.iter().enumerate() {
            if i > 0 {
                out.push(',');
            }
            out.push_str(&v.to_string());
        }
        out.push_str("],\n");
    }
    out.push_str("];\n\n");

    out.push_str("/// Frozen state-indexed codebook tables (Q12), one per `L`.\n");
    out.push_str("#[rustfmt::skip]\n");
    out.push_str("pub static CODEBOOK_LUTS: &[&[i32]] = &[\n");
    for (k, t) in code.iter().enumerate() {
        out.push_str(&format!("    // L = {}\n    &[", lo as usize + k));
        for (i, v) in t.iter().enumerate() {
            if i > 0 {
                out.push(',');
            }
            out.push_str(&v.to_string());
        }
        out.push_str("],\n");
    }
    out.push_str("];\n");

    print!("{out}");
    eprintln!("[freeze-lut] L in [{lo},{hi}], golden FNV-1a = 0x{golden:016x}");
}
